class Solution:
    def largestInteger(self, num: int) -> int:
        s = str(num)
        evens = []
        odds = []
        for c in s:
            digit = int(c)
            if digit % 2 == 0:
                evens.append(c)
            else:
                odds.append(c)
        evens.sort(reverse=True)
        odds.sort(reverse=True)
        result = []
        e = o = 0
        for c in s:
            digit = int(c)
            if digit % 2 == 0:
                result.append(evens[e])
                e += 1
            else:
                result.append(odds[o])
                o += 1
        return int(''.join(result))

